import json
import re
from collections import defaultdict

# Load data
reviews_2016_users = locals().get('var_functions.query_db:26', [])
businesses_file = locals().get('var_functions.query_db:46', '')

# Load from file if needed
if isinstance(reviews_2016_users, str) and reviews_2016_users.endswith('.json'):
    with open(reviews_2016_users, 'r') as f:
        reviews_2016_users = json.load(f)

# Load full businesses data
if businesses_file and isinstance(businesses_file, str) and businesses_file.endswith('.json'):
    with open(businesses_file, 'r') as f:
        all_businesses = json.load(f)
else:
    all_businesses = []

# Map reviews by business_id (convert businessref_X to businessid_X)
review_by_business = defaultdict(list)
for review in reviews_2016_users:
    business_ref = review.get('business_ref', '')
    if business_ref:
        business_id = business_ref.replace('businessref_', 'businessid_')
        review_by_business[business_id].append(review)

# Create business_id to categories mapping with better parsing
business_categories = {}

for business in all_businesses:
    business_id = business.get('business_id', '')
    description = business.get('description', '')

    if not business_id or not description:
        continue

    categories = []
    desc = description

    # Pattern 1: Look for lists after keywords like "in", "including", "offers"
    patterns = [
        r'(?:in|including|offers|provides|specializes in|ranging from|features)\s+([^\.]+)'
    ]

    found_categories = False
    for pattern in patterns:
        matches = re.findall(pattern, desc, re.IGNORECASE)
        if matches:
            for match in matches:
                # Clean up the match
                match = match.strip()
                # Remove trailing phrases
                match = re.split(r'\.(?![a-z])|\bmaking\b|\bperfect for\b|\bto meet\b', match)[0].strip()

                # Split by "and" and commas
                parts = re.split(r',\s*|\sand\s', match)
                for part in parts:
                    part = part.strip()
                    # Clean up the part
                    part = re.sub(r'^[^a-zA-Z]*', '', part)  # Remove leading non-letters
                    part = re.sub(r'[^a-zA-Z\s&/-]+$', '', part)  # Remove trailing non-letters
                    part = part.strip()

                    if len(part) < 3:
                        continue

                    lower_part = part.lower()
                    # Skip location markers and common words
                    if any(skip in lower_part for skip in ['located', 'avenue', 'street', 'road', 'boulevard', 'drive', 'suite', 'floor', 'this ', 'the ', 'making', 'perfect for']):
                        continue

                    # Skip if contains numbers (likely address)
                    if re.search(r'\d', part):
                        continue

                    if part:
                        categories.append(part)
                        found_categories = True

    # Pattern 2: Extract capitalized phrases that are likely categories
    if not found_categories:
        # Find comma-separated capitalized phrases
        potential_categories = re.findall(r'\b[A-Z][a-zA-Z&\s/-]+(?:,\s*[A-Z][a-zA-Z&\s/-]+)*', desc)

        for match in potential_categories:
            parts = match.split(',')
            for part in parts:
                part = part.strip()
                if 3 <= len(part) <= 50:
                    lower_part = part.lower()
                    if lower_part not in ['this', 'offers', 'provides', 'including', 'located', 'located at']:
                        if not any(loc in lower_part for loc in ['avenue', 'street', 'road', 'boulevard', 'drive', 'suite', 'floor', 'highway', 'suite']):
                            if not re.search(r'\d', part):
                                categories.append(part)
                                found_categories = True

    # Pattern 3: Look for "category1, category2, and category3" format
    if not found_categories:
        # Find "X, Y, and Z" patterns
        and_pattern = re.findall(r'(?:[A-Z][a-zA-Z&\s/-]+,\s*)+(?:and\s*)?[A-Z][a-zA-Z&\s/-]+', desc)
        for match in and_pattern:
            # Remove "and" and split by commas
            match = match.replace(' and ', ',')
            parts = match.split(',')
            for part in parts:
                part = part.strip()
                if len(part) >= 3:
                    lower_part = part.lower()
                    if not any(skip in lower_part for skip in ['avenue', 'street', 'road', 'suite', 'this', 'the', 'making', 'offering']):
                        if not re.search(r'\d', part):
                            categories.append(part)
                            found_categories = True

    # Deduplicate categories
    if categories:
        seen = set()
        unique_categories = []
        for cat in categories:
            if cat not in seen:
                seen.add(cat)
                unique_categories.append(cat)
        business_categories[business_id] = unique_categories

# Count reviews by category
category_review_counts = defaultdict(int)
for business_id, reviews in review_by_business.items():
    categories = business_categories.get(business_id, [])
    review_count = len(reviews)
    for category in categories:
        category_review_counts[category] += review_count

# Get top 5 categories
top_5_categories = sorted(category_review_counts.items(), key=lambda x: x[1], reverse=True)[:5]

result = {
    "top_5_business_categories": top_5_categories,
    "total_reviews_analyzed": len(reviews_2016_users),
    "businesses_reviewed": len(review_by_business)
}

print('__RESULT__:')
print(json.dumps(result, indent=2))

